// ─────────────────────────────────────────────────────────────────────────────
// Standup bot setup. Edit this file to configure your team and tools.
// Secrets (API keys, IDs) live in .env.local, never here.
// ─────────────────────────────────────────────────────────────────────────────

export type Member = {
  slackEmail: string; // used to look up their Slack user + Composio connections
  githubUsername: string;
  standupTime?: string; // "HH:MM" 24h in THEIR timezone; defaults below
  standupTimezone?: string; // IANA tz, e.g. "Europe/Rome"; defaults below
};

export type Toolkit = {
  slug: string; // Composio toolkit slug
  label: string; // shown on Connect buttons
  emoji: string; // leads the bullet in the draft
  draftInstruction: string; // injected into the draft prompt when connected
};

// Model used to write the draft, via the Vercel AI Gateway.
export const MODEL = "anthropic/claude-sonnet-4-5" as const;

// ─── Schedule ────────────────────────────────────────────────────────────────
// The cron runs every 30 min on weekdays; each member is reminded in the slot
// containing their standupTime, evaluated in their own timezone.
export const DEFAULT_STANDUP_TIMEZONE = "America/Los_Angeles";
export const DEFAULT_STANDUP_TIME = "10:00";
export const CRON_SLOT_MINUTES = 30;
// When true, every member is "due" on every cron run, ignoring standupTime.
// Set false in production so per-person times are honored.
export const DEMO_MODE = false;

// ─── Team ────────────────────────────────────────────────────────────────────
export const standupChannel = "#standup";

export const team: Member[] = [
  { slackEmail: "you@example.com", githubUsername: "your-handle" },
  { slackEmail: "teammate@example.com", githubUsername: "teammate-handle" },
  // A per-person time and timezone override the defaults below:
  { slackEmail: "alberto@example.com", githubUsername: "alberto-handle", standupTimezone: "Europe/Rome" },
];

// GitHub org that standup drafts are scoped to. Activity in other orgs and
// personal repos is ignored. Change this to your org.
export const GITHUB_ORG = "your-github-org";

// ─── Toolkit catalogue ───────────────────────────────────────────────────────
// Every toolkit a member can connect. The draft agent gets a Composio tool-router
// session scoped to whichever of these each member has connected. Delete what you
// don't want; edit draftInstruction to change how each source is summarized.
export const TOOLKITS: Toolkit[] = [
  {
    slug: "github",
    label: "GitHub",
    emoji: "🔧",
    draftInstruction:
      `GitHub: find PRs they opened or merged in the time range, SCOPED TO THE ${GITHUB_ORG} ORG ONLY. Always include \`org:${GITHUB_ORG}\` in the search query. Ignore other orgs and personal repos. For each meaningful PR write a one-liner explaining its PURPOSE, prefixed with a status emoji: 🟣 merged, 🟢 open, ⚪️ draft, 🔴 closed. Include the *#number*.`,
  },
  {
    slug: "linear",
    label: "Linear",
    emoji: "📋",
    draftInstruction:
      "Linear: find issues they created, updated, or completed in the time range. Summarize the meaningful ones (📋), focusing on what moved forward.",
  },
  {
    slug: "notion",
    label: "Notion",
    emoji: "📝",
    draftInstruction:
      "Notion: find pages/docs they created or edited in the time range. Summarize the doc work as a one-liner (📝) describing what the doc is for.",
  },
  {
    slug: "googlecalendar",
    label: "Google Calendar",
    emoji: "📅",
    draftInstruction:
      "Google Calendar: find their meetings/events in the time range. Only mention notable ones that reflect real work (📅), not routine blocks.",
  },
  {
    slug: "googlemeet",
    label: "Google Meet",
    emoji: "🎥",
    draftInstruction:
      "Google Meet (context only): optionally read meeting details/transcripts for context. Do not list meetings just for existing.",
  },
  {
    slug: "zoom",
    label: "Zoom",
    emoji: "🎥",
    draftInstruction:
      "Zoom (context only): optionally read meeting info/recordings in the time range for extra context.",
  },
  {
    slug: "granola_mcp",
    label: "Granola",
    emoji: "🎙️",
    draftInstruction:
      "Granola (context only): optionally read meeting transcripts in the time range for additional context.",
  },
  {
    slug: "slack",
    label: "Slack",
    emoji: "💬",
    draftInstruction:
      "Slack (context only): optionally look at messages they sent in public channels for context. Do not quote verbatim.",
  },
];

export const TOOLKIT_SLUGS = TOOLKITS.map((t) => t.slug);

import type { VercelRequest, VercelResponse } from "@vercel/node";
import { team, standupChannel, TOOLKITS } from "../../standup.config";
import { formatToday, isMemberDue } from "../_utils/schedule";
import { getConnectedIntegrations } from "../_utils/composio";
import { buildReminderMenu } from "../_utils/blocks";
import {
  findChannelId,
  getRecentMessages,
  postMessage,
  getPermalink,
  findUserIdByEmail,
  sendDmBlocks,
} from "../_utils/slack";
import { env } from "../_utils/env";

export const maxDuration = 300;

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.headers.authorization !== `Bearer ${env.CRON_SECRET}`) {
    return res.status(401).json({ error: "Unauthorized" });
  }

  const results: { member: string; status: string }[] = [];
  // One shared thread per calendar day, keyed to the team timezone on purpose:
  // everyone posts into the same thread even though reminders fire in each
  // member's local time. (Per-member timezone here would fork the thread.)
  const today = formatToday();

  // Only members whose configured time falls in this 30-minute slot.
  const dueMembers = team.filter(isMemberDue);
  if (dueMembers.length === 0) {
    return res.status(200).json({ status: "no members due this slot" });
  }

  try {
    // Resolve the channel and find or create today's thread.
    const channelId = await findChannelId(standupChannel);
    if (!channelId) {
      return res.status(500).json({
        error: `Channel ${standupChannel} not found. Is the bot a member?`,
      });
    }

    const parentText = `📅 *Daily Standup: ${today}*\n_Standups are posted in this thread as folks confirm._`;
    // Scan a generous window for today's parent. A high-volume channel could push
    // it past this; a production bot would paginate or persist the thread ts.
    const recent = await getRecentMessages(channelId, 200);
    const threadTs =
      recent.find((m) => m.text.includes("Daily Standup") && m.text.includes(today))
        ?.ts ?? (await postMessage(channelId, parentText))?.ts;
    if (!threadTs) {
      return res.status(500).json({ error: "Failed to create daily thread" });
    }
    // Narrowed const so the per-member closure below sees a plain string.
    const thread = threadTs;
    const threadUrl = (await getPermalink(channelId, thread)) ?? "";

    // DM each due member the reminder menu, in parallel.
    async function processMember(
      member: (typeof team)[number]
    ): Promise<{ member: string; status: string }> {
      try {
        const [connected, userId] = await Promise.all([
          getConnectedIntegrations(member.slackEmail),
          findUserIdByEmail(member.slackEmail),
        ]);
        const showConnect = connected.length < TOOLKITS.length;

        if (!userId) {
          return { member: member.slackEmail, status: "error: no slack user" };
        }

        const menu = buildReminderMenu(
          threadUrl,
          { memberEmail: member.slackEmail, threadTs: thread, channelId: channelId! },
          showConnect
        );
        const dm = await sendDmBlocks(userId, menu.text, menu.blocks);
        return {
          member: member.slackEmail,
          status: dm ? "reminded" : "error: dm failed",
        };
      } catch (error) {
        const errMsg = error instanceof Error ? error.message : String(error);
        return { member: member.slackEmail, status: `error: ${errMsg}` };
      }
    }

    results.push(...(await Promise.all(dueMembers.map(processMember))));
    return res.status(200).json({ threadTs, threadUrl, results });
  } catch (err) {
    return res.status(500).json({
      error: "Internal server error",
      message: err instanceof Error ? err.message : String(err),
      results,
    });
  }
}

import type { VercelRequest, VercelResponse } from "@vercel/node";
import { waitUntil } from "@vercel/functions";
import crypto from "crypto";
import { team, TOOLKITS } from "../standup.config";
import { memberName } from "./_utils/schedule";
import {
  ACTION_DRAFT,
  ACTION_CONNECT,
  ACTION_CONFIRM,
  ACTION_EDIT,
  MODAL_EDIT_SUBMIT,
  EDIT_INPUT_BLOCK,
  EDIT_INPUT_ACTION,
  buildLoadingMessage,
  buildDraftMessage,
  buildPostedMessage,
  buildCopyMessage,
  buildConnectMenu,
  buildEditModal,
  extractDraft,
  StandupContext,
} from "./_utils/blocks";
import { getConnectedIntegrations, getConnectLink } from "./_utils/composio";
import { generateDraftText } from "./_utils/agent";
import {
  openModal,
  postMessage,
  updateMessage,
  postAsUser,
  getPermalink,
} from "./_utils/slack";
import { env } from "./_utils/env";

export const maxDuration = 300;

// Disable Vercel's body parsing: Slack signs the EXACT raw bytes.
export const config = { api: { bodyParser: false } };

// The subset of a Slack interaction payload this handler reads.
type SlackAction = { action_id?: string; value?: string };
type SlackInteraction = {
  type?: string;
  trigger_id?: string;
  actions?: SlackAction[];
  message?: { ts?: string; blocks?: Array<{ block_id?: string; text?: { text?: string } }> };
  container?: { channel_id?: string };
  channel?: { id?: string };
  view?: {
    callback_id?: string;
    private_metadata?: string;
    state?: { values?: Record<string, Record<string, { value?: string }>> };
  };
};
// What buildEditModal stuffs into the modal's private_metadata.
type StoredMeta = StandupContext & { dmChannel?: string; dmTs?: string };

function readRawBody(req: VercelRequest): Promise<string> {
  return new Promise((resolve) => {
    if (typeof req.body === "string") return resolve(req.body);
    if (req.body && Buffer.isBuffer(req.body)) return resolve(req.body.toString("utf8"));
    let data = "";
    req.setEncoding?.("utf8");
    req.on("data", (c) => (data += c));
    req.on("end", () => resolve(data));
    req.on("error", () => resolve(data));
  });
}

// Implements Slack's documented request-verification algorithm (v0 basestring,
// 5-minute replay window, constant-time HMAC-SHA256 compare):
// https://docs.slack.dev/authentication/verifying-requests-from-slack
function verifySlackSignature(
  rawBody: string,
  signature: string | undefined,
  timestamp: string | undefined,
  signingSecret: string
): boolean {
  if (!signature || !timestamp) return false;
  const age = Math.abs(Date.now() / 1000 - Number(timestamp));
  if (!Number.isFinite(age) || age > 300) return false;
  const hmac =
    "v0=" +
    crypto
      .createHmac("sha256", signingSecret)
      .update(`v0:${timestamp}:${rawBody}`)
      .digest("hex");
  try {
    return crypto.timingSafeEqual(Buffer.from(hmac), Buffer.from(signature));
  } catch {
    return false;
  }
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }

  const rawBody = await readRawBody(req);
  if (
    !verifySlackSignature(
      rawBody,
      req.headers["x-slack-signature"] as string,
      req.headers["x-slack-request-timestamp"] as string,
      env.SLACK_SIGNING_SECRET
    )
  ) {
    return res.status(401).json({ error: "Invalid signature" });
  }

  const payload: SlackInteraction = JSON.parse(
    new URLSearchParams(rawBody).get("payload") || "{}"
  );

  // Modal submit (edits): fast, respond inline.
  if (payload.type === "view_submission") {
    if (payload.view?.callback_id === MODAL_EDIT_SUBMIT) {
      const meta: StoredMeta = JSON.parse(payload.view.private_metadata || "{}");
      const ctx: StandupContext = {
        memberEmail: meta.memberEmail,
        threadTs: meta.threadTs,
        channelId: meta.channelId,
      };
      const edited =
        payload.view.state?.values?.[EDIT_INPUT_BLOCK]?.[EDIT_INPUT_ACTION]
          ?.value ?? "";
      const msg = buildDraftMessage(edited, ctx);
      if (meta.dmChannel && meta.dmTs) {
        await updateMessage(meta.dmChannel, meta.dmTs, msg.text, msg.blocks);
      }
    }
    return res.status(200).send("");
  }

  if (payload.type !== "block_actions") return res.status(200).send("");

  const action = payload.actions?.[0];
  const ctx: StandupContext = JSON.parse(action?.value || "{}");
  const dmChannel = payload.container?.channel_id ?? payload.channel?.id;
  const dmTs = payload.message?.ts;
  if (!dmChannel || !dmTs) return res.status(200).send("");

  // Edit opens a modal: must use trigger_id within ~3s, so handle inline.
  if (action?.action_id === ACTION_EDIT) {
    const draft = extractDraft(payload.message ?? {});
    await openModal(
      payload.trigger_id ?? "",
      buildEditModal(draft, ctx, { channel: dmChannel, ts: dmTs })
    );
    return res.status(200).send("");
  }

  // Slow work (AI draft, OAuth links, posting): ack within Slack's 3s window,
  // then run via waitUntil, which keeps the function alive after the response is
  // sent. A plain post-send await would be frozen by Vercel.
  waitUntil(
    processSlowAction(action, ctx, dmChannel, dmTs, payload).catch(async (err) => {
      // Don't leave the member stuck on the loading message: log and tell them.
      console.error("standup interaction failed:", err);
      await postMessage(
        dmChannel,
        "⚠️ Something went wrong handling that. Please try again."
      ).catch(() => {});
    })
  );
  return res.status(200).send("");
}

async function processSlowAction(
  action: SlackAction | undefined,
  ctx: StandupContext,
  dmChannel: string,
  dmTs: string,
  payload: SlackInteraction
) {
  const member = team.find((m) => m.slackEmail === ctx.memberEmail);

  if (action?.action_id === ACTION_DRAFT) {
    const loading = buildLoadingMessage();
    await updateMessage(dmChannel, dmTs, loading.text, loading.blocks);

    const connected = await getConnectedIntegrations(ctx.memberEmail);
    const draft =
      member && connected.length
        ? await generateDraftText(member, connected)
        : "";
    const msg = buildDraftMessage(draft, ctx);
    await updateMessage(dmChannel, dmTs, msg.text, msg.blocks);
    return;
  }

  if (action?.action_id === ACTION_CONNECT) {
    const connected = await getConnectedIntegrations(ctx.memberEmail);
    const unconnected = TOOLKITS.filter((t) => !connected.includes(t.slug));
    const links = (
      await Promise.all(
        unconnected.map(async (t) => {
          const url = await getConnectLink(ctx.memberEmail, t.slug);
          return url ? { label: t.label, url } : null;
        })
      )
    ).filter(Boolean) as { label: string; url: string }[];

    if (unconnected.length === 0) {
      await postMessage(dmChannel, "You're already connected to everything! 🎉");
    } else if (links.length === 0) {
      // Toolkits remain, but every connect link failed to generate.
      await postMessage(
        dmChannel,
        "⚠️ Couldn't generate connect links right now. Please try again in a moment."
      );
    } else {
      const menu = buildConnectMenu(links);
      await postMessage(dmChannel, menu.text, { blocks: menu.blocks });
    }
    return;
  }

  if (action?.action_id === ACTION_CONFIRM) {
    const draft = extractDraft(payload.message ?? {});
    // Swap the buttons out immediately so a double-click can't post twice.
    const posting = buildLoadingMessage("Posting your standup…");
    await updateMessage(dmChannel, dmTs, posting.text, posting.blocks);

    const name = member ? memberName(member) : ctx.memberEmail;
    const connected = await getConnectedIntegrations(ctx.memberEmail);

    let posted = false;
    if (connected.includes("slack")) {
      posted = await postAsUser(
        ctx.memberEmail,
        ctx.channelId,
        `*${name}'s standup*\n${draft}`,
        ctx.threadTs
      );
    }

    if (posted) {
      const m = buildPostedMessage(draft);
      await updateMessage(dmChannel, dmTs, m.text, m.blocks);
    } else {
      // No personal Slack (or post failed): give them copyable text.
      const url = (await getPermalink(ctx.channelId, ctx.threadTs)) ?? "";
      const m = buildCopyMessage(draft, url);
      await updateMessage(dmChannel, dmTs, m.text, m.blocks);
    }
    return;
  }
}

import { config } from "dotenv";

// Load .env.local for local runs (scripts, `vercel dev`). Harmless on Vercel,
// where the file is absent and real environment variables are already set.
config({ path: ".env.local" });

// Validate every required var once at import time, so a misconfigured deploy
// fails fast with a clear message instead of a vague error mid-request.
const REQUIRED = [
  "COMPOSIO_API_KEY",
  "COMPOSIO_SLACKBOT_AUTH_CONFIG_ID", // the "slackbot" auth config (ac_...)
  "SLACK_SIGNING_SECRET", // verifies Slack interactivity requests
  "CRON_SECRET", // shared secret the Vercel cron presents
] as const;

type EnvKey = (typeof REQUIRED)[number];

function loadEnv(): Record<EnvKey, string> {
  const missing = REQUIRED.filter((key) => !process.env[key]);
  if (missing.length > 0) {
    throw new Error(
      `Missing required environment variable(s): ${missing.join(", ")}.\n` +
        `Copy .env.local.example to .env.local and fill them in.`
    );
  }
  return Object.fromEntries(
    REQUIRED.map((key) => [key, process.env[key]!])
  ) as Record<EnvKey, string>;
}

export const env = loadEnv();

import dayjs from "dayjs";
import utc from "dayjs/plugin/utc";
import timezone from "dayjs/plugin/timezone";
import {
  Member,
  DEFAULT_STANDUP_TIME,
  DEFAULT_STANDUP_TIMEZONE,
  CRON_SLOT_MINUTES,
  DEMO_MODE,
} from "../../standup.config";

dayjs.extend(utc);
dayjs.extend(timezone);

/** "soham.basu@…" → "Soham Basu". Keeps raw emails out of the public channel. */
export function memberName(member: Member): string {
  return member.slackEmail
    .split("@")[0]
    .split(/[._]/)
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
    .join(" ");
}

export function formatToday(): string {
  return dayjs().tz(DEFAULT_STANDUP_TIMEZONE).format("dddd, MMMM D, YYYY");
}

/** Draft lookback: Monday reaches back to Friday, else the previous day.
 *  Computed in the member's own timezone so the window matches their day. */
export function lookbackWindow(
  timezone: string = DEFAULT_STANDUP_TIMEZONE
): { date: string; label: string } {
  const now = dayjs().tz(timezone);
  const days = now.day() === 1 ? 3 : 1;
  return {
    date: now.subtract(days, "day").format("YYYY-MM-DD"),
    label: days === 1 ? "since yesterday" : "since your last standup",
  };
}

const memberStandupTime = (m: Member) => m.standupTime ?? DEFAULT_STANDUP_TIME;
const memberTimezone = (m: Member) => m.standupTimezone ?? DEFAULT_STANDUP_TIMEZONE;

/** Is this member due in the current cron slot, evaluated in their timezone? */
export function isMemberDue(member: Member): boolean {
  if (DEMO_MODE) return true;
  const now = dayjs().tz(memberTimezone(member));
  const nowMin = now.hour() * 60 + now.minute();
  const slotStart = Math.floor(nowMin / CRON_SLOT_MINUTES) * CRON_SLOT_MINUTES;
  const [h, m] = memberStandupTime(member).split(":").map(Number);
  const memberMin = h * 60 + m;
  return memberMin >= slotStart && memberMin < slotStart + CRON_SLOT_MINUTES;
}

import { Composio } from "@composio/core";
import { VercelProvider } from "@composio/vercel";
import { TOOLKIT_SLUGS } from "../../standup.config";
import { env } from "./env";

export const composio = new Composio({
  apiKey: env.COMPOSIO_API_KEY,
  provider: new VercelProvider(),
});

// The bot's own Composio user. The slackbot OAuth connection lives here, so all
// bot Slack actions (posting to the channel, DMing members) execute as the bot.
export const BOT_USER = "default";

/** Active connected accounts for a user, optionally filtered to one toolkit.
 *  Filters server-side via `statuses` so we never see stale/expired ones. */
export async function listActiveAccounts(userId: string, toolkitSlug?: string) {
  const res = await composio.connectedAccounts.list({
    userIds: [userId],
    statuses: ["ACTIVE"],
    ...(toolkitSlug ? { toolkitSlugs: [toolkitSlug] } : {}),
  });
  return res.items;
}

// The bot's slackbot connected-account ID. proxyExecute needs it so the call
// authenticates as the bot (the project has several connections, so we can't
// rely on a default-account fallback). Resolved once and memoized.
let botAccountIdPromise: Promise<string | undefined> | undefined;
function getBotAccountId(): Promise<string | undefined> {
  botAccountIdPromise ??= listActiveAccounts(BOT_USER, "slackbot")
    .then((accounts) => accounts[0]?.id)
    .then((id) => {
      // Don't cache a miss: if the bot isn't connected yet, retry next call so a
      // later setup/OAuth is picked up without waiting for a cold start.
      if (!id) botAccountIdPromise = undefined;
      return id;
    });
  return botAccountIdPromise;
}

// Wraps Composio's proxyExecute to call any Slack Web API endpoint as the bot
// (or a member, via accountId). Covers what the named SLACKBOT_* tools don't,
// like views.open for modals.
export async function slackApi<T = unknown>(
  endpoint: string,
  method: "GET" | "POST",
  body?: Record<string, unknown>,
  accountId?: string // override the bot account (e.g. post as a member)
): Promise<T> {
  const connectedAccountId = accountId ?? (await getBotAccountId());
  const res = await composio.tools.proxyExecute({
    endpoint,
    method,
    ...(body ? { body } : {}),
    ...(connectedAccountId ? { connectedAccountId } : {}),
  });
  // proxyExecute wraps Slack's JSON response in `data`.
  return ((res as { data?: unknown }).data ?? res) as T;
}

/** Run a named Composio tool as a user (the bot by default). This is the normal
 *  path for actions a SLACKBOT or SLACK tool covers (sending a message, even
 *  one with Block Kit buttons, updating one, posting as a member). Returns the
 *  tool's `data`, which is the Slack API response. */
export async function slackTool<T = Record<string, unknown>>(
  slug: string,
  args: Record<string, unknown>,
  userId: string = BOT_USER
): Promise<T> {
  const res = await composio.tools.execute(slug, { userId, arguments: args });
  return (res.data ?? {}) as T;
}

/** Which catalogue toolkits the member has actively connected. */
export async function getConnectedIntegrations(
  memberEmail: string
): Promise<string[]> {
  const active = await listActiveAccounts(memberEmail);
  const slugs = new Set(active.map((a) => a.toolkit.slug));
  return TOOLKIT_SLUGS.filter((s) => slugs.has(s));
}

/** Generate an OAuth connect link for one toolkit, for one member. */
export async function getConnectLink(
  memberEmail: string,
  toolkitSlug: string
): Promise<string | null> {
  try {
    const conn = await composio.toolkits.authorize(memberEmail, toolkitSlug);
    return conn.redirectUrl ?? null;
  } catch {
    return null;
  }
}

/**
 * A tool-router session scoped to the given toolkits. `session.tools()` returns
 * Composio's research meta-tools (search/execute/workbench) limited to these
 * toolkits. `manageConnections: false` strips the connection meta-tools so the
 * draft agent can research but never initiate an OAuth flow mid-draft.
 */
export async function createToolRouterSession(
  memberEmail: string,
  toolkitSlugs: string[]
) {
  return composio.sessions.create(memberEmail, {
    toolkits: toolkitSlugs,
    manageConnections: false,
  });
}

import { slackApi, slackTool, listActiveAccounts } from "./composio";

// The subset of Slack Web API response fields this bot reads. proxyExecute
// returns the raw Slack JSON, so one shared shape keeps call sites typed.
type SlackResponse = {
  ok?: boolean;
  error?: string;
  ts?: string;
  channel?: string;
  permalink?: string;
  user?: { id?: string };
  channels?: Array<{ id: string; name: string }>;
  messages?: Array<{ ts: string; text?: string }>;
  response_metadata?: { next_cursor?: string };
};

export async function findUserIdByEmail(email: string): Promise<string | null> {
  const data = await slackApi<SlackResponse>(
    `/users.lookupByEmail?email=${encodeURIComponent(email)}`,
    "GET"
  );
  return data.user?.id ?? null;
}

/** Resolve a channel ID from a "#channel-name" (or bare name). */
export async function findChannelId(channelName: string): Promise<string | null> {
  const name = channelName.replace(/^#/, "");
  let cursor: string | undefined;
  for (let i = 0; i < 10; i++) {
    const qs = new URLSearchParams({
      types: "public_channel,private_channel",
      limit: "200",
      ...(cursor ? { cursor } : {}),
    });
    const data = await slackApi<SlackResponse>(`/conversations.list?${qs.toString()}`, "GET");
    const match = (data.channels ?? []).find((c) => c.name === name);
    if (match) return match.id;
    cursor = data.response_metadata?.next_cursor || undefined;
    if (!cursor) break;
  }
  return null;
}

/** Fetch recent top-level messages in a channel (newest first; threaded replies excluded). */
export async function getRecentMessages(
  channelId: string,
  limit = 50
): Promise<Array<{ ts: string; text: string }>> {
  const data = await slackApi<SlackResponse>(
    `/conversations.history?channel=${encodeURIComponent(channelId)}&limit=${limit}`,
    "GET"
  );
  return (data.messages ?? []).map((m) => ({ ts: m.ts, text: m.text ?? "" }));
}

export async function postMessage(
  channel: string,
  text: string,
  opts?: { thread_ts?: string; blocks?: unknown[] }
): Promise<{ ts: string } | null> {
  // SLACKBOT_SEND_MESSAGE is the named tool: markdown_text for prose, or Block
  // Kit `blocks` (buttons included). channel must be a channel/DM id, not a user id.
  const data = await slackTool<SlackResponse>("SLACKBOT_SEND_MESSAGE", {
    channel,
    ...(opts?.blocks ? { blocks: opts.blocks } : { markdown_text: text }),
    ...(opts?.thread_ts ? { thread_ts: opts.thread_ts } : {}),
  });
  return data.ts ? { ts: data.ts } : null;
}

// Stays on the proxy: this opens a DM by passing a user id as the channel, which
// the raw chat.postMessage allows but SLACKBOT_SEND_MESSAGE rejects (it wants a
// pre-opened D… channel id). The proxy lets us DM the member in one call.
export async function sendDmBlocks(
  userId: string,
  text: string,
  blocks: unknown[]
): Promise<{ channel: string; ts: string } | null> {
  const data = await slackApi<SlackResponse>("/chat.postMessage", "POST", {
    channel: userId,
    text,
    blocks,
  });
  if (!data.ok || !data.channel || !data.ts) return null;
  return { channel: data.channel, ts: data.ts };
}

/** Update an existing message (e.g. swap the draft after an edit). The named
 *  tool SLACKBOT_UPDATES_A_MESSAGE takes Block Kit blocks just like sending. */
export async function updateMessage(
  channel: string,
  ts: string,
  _text: string,
  blocks: unknown[]
): Promise<boolean> {
  const data = await slackTool<SlackResponse>("SLACKBOT_UPDATES_A_MESSAGE", { channel, ts, blocks });
  return data.ok !== false;
}

/** Permalink to a message (used to link members to today's thread). */
export async function getPermalink(
  channel: string,
  ts: string
): Promise<string | null> {
  const data = await slackApi<SlackResponse>(
    `/chat.getPermalink?channel=${encodeURIComponent(channel)}&message_ts=${ts}`,
    "GET"
  );
  return data.permalink ?? null;
}

/** The member's OWN active Slack connected-account id (for posting as them). */
async function getMemberSlackAccountId(
  memberEmail: string
): Promise<string | undefined> {
  const [active] = await listActiveAccounts(memberEmail, "slack");
  return active?.id;
}

/**
 * Post into the thread AS the member, using their personal Slack connection.
 * SLACK_SEND_MESSAGE (the slack user toolkit) run under their email as the
 * userId, so it posts under their name. Returns false if they have no active
 * personal Slack account.
 */
export async function postAsUser(
  memberEmail: string,
  channel: string,
  text: string,
  threadTs: string
): Promise<boolean> {
  const accountId = await getMemberSlackAccountId(memberEmail);
  if (!accountId) return false;
  const data = await slackTool<SlackResponse>(
    "SLACK_SEND_MESSAGE",
    { channel, markdown_text: text, thread_ts: threadTs },
    memberEmail
  );
  return data.ok !== false;
}

/** Open a modal in response to a button click (needs trigger_id, <3s). */
export async function openModal(triggerId: string, view: unknown): Promise<boolean> {
  const data = await slackApi<SlackResponse>("/views.open", "POST", { trigger_id: triggerId, view });
  return !!data.ok;
}

import { generateText, stepCountIs } from "ai";
import { Member, MODEL, TOOLKITS, GITHUB_ORG } from "../../standup.config";
import { lookbackWindow } from "./schedule";
import { createToolRouterSession } from "./composio";

/** The standup draft prompt, adapted to whichever toolkits the member connected. */
function buildDraftPrompt(
  member: Member,
  window: { date: string; label: string },
  connectedSlugs: string[]
): string {
  const connected = TOOLKITS.filter((t) => connectedSlugs.includes(t.slug));
  const sources = connected.map((t) => `  - ${t.draftInstruction}`).join("\n");
  const emojiLegend = connected.map((t) => `${t.emoji} ${t.label}`).join(", ");

  return `You are writing @${member.githubUsername}'s daily standup, covering
${window.label} (everything since ${window.date}).

You have a Composio tool-router session with these tools connected:
${connected.map((t) => t.label).join(", ")}.
Use the meta-tools to research yourself: search for the right tool per source,
then execute it. Do NOT guess activity. Investigate first, then write.

IMPORTANT: All tools above are ALREADY connected. Do NOT attempt to connect,
authenticate, or generate OAuth links. If a tool call fails, skip that source.
Never ask the user to connect anything.

What to look at (ONLY these connected sources):
${sources}

Keep tool requests small (filter by date, ~10 items, no full transcripts).

Output rules:
  - 2 to 5 atomic, one-line updates. Prune noise.
  - Start each line with the right source emoji: ${emojiLegend}. GitHub PRs use
    🟣 merged, 🟢 open, ⚪️ draft, 🔴 closed and include the *#number*.
  - State WHAT they did and WHY it matters, plainly. Facts only, no speculation.
  - NEVER use em dashes. Use colons, commas, or separate sentences.
  - LINKS: this is posted to Slack, which does NOT support Markdown links. NEVER
    write [text](url). Use Slack's link syntax <url|text> instead, e.g.
    <https://github.com/${GITHUB_ORG}/repo/pull/893|#893>. A bare URL is also fine.
  - CRITICAL: your reply is posted to Slack VERBATIM. It must contain ONLY the
    bullet lines, each starting with its source emoji. No preamble ("Here's the
    standup"), no narration ("I found 3 PRs"), no headings, no closing remarks,
    no sign-off. The very first character of your reply is the first bullet's emoji.
  - If no activity in range, your entire reply is exactly: "📭 No tracked activity ${window.label}."`;
}

/**
 * Generate a member's standup draft by researching their CONNECTED tools. Spins
 * up a Composio tool-router session scoped to those toolkits and lets the agent
 * drive the meta-tools to gather activity. Returns the draft text only.
 */
export async function generateDraftText(
  member: Member,
  connectedSlugs: string[]
): Promise<string> {
  if (connectedSlugs.length === 0) return "";

  const session = await createToolRouterSession(member.slackEmail, connectedSlugs);
  const tools = await session.tools();

  const { text } = await generateText({
    model: MODEL,
    system: buildDraftPrompt(member, lookbackWindow(member.standupTimezone), connectedSlugs),
    prompt: `Research and write @${member.githubUsername}'s standup update.`,
    tools,
    stopWhen: stepCountIs(40),
  });

  return text.trim();
}

// Block Kit builders for the standup menu / confirm / edit / connect flow.
// Plain data (no agent involvement) keeps the interactive messages deterministic.

export const ACTION_DRAFT = "standup_draft";
export const ACTION_CONNECT = "standup_connect";
export const ACTION_CONFIRM = "standup_confirm";
export const ACTION_EDIT = "standup_edit";
export const MODAL_EDIT_SUBMIT = "standup_edit_submit";
export const EDIT_INPUT_BLOCK = "standup_edit_block";
export const EDIT_INPUT_ACTION = "standup_edit_input";
// Stable id for the draft-body section, so the handler can recover the draft
// text by block_id instead of a fragile positional index.
export const DRAFT_BODY_BLOCK = "standup_draft_body";

// Context threaded through buttons/modals so the handler knows who/where without
// re-deriving it. Kept small (button `value` is capped at 2000 chars).
export type StandupContext = {
  memberEmail: string;
  threadTs: string; // parent daily-thread message ts
  channelId: string; // the standup channel's ID
};

/** The daily reminder "menu": a nudge + Draft button (+ Connect if applicable). */
export function buildReminderMenu(
  threadUrl: string,
  ctx: StandupContext,
  showConnect: boolean
) {
  const value = JSON.stringify(ctx);
  const buttons: Record<string, unknown>[] = [
    {
      type: "button",
      style: "primary",
      text: { type: "plain_text", text: "📝 Draft", emoji: true },
      action_id: ACTION_DRAFT,
      value,
    },
  ];
  if (showConnect) {
    buttons.push({
      type: "button",
      text: { type: "plain_text", text: "🔌 Connect more tools", emoji: true },
      action_id: ACTION_CONNECT,
      value,
    });
  }
  return {
    text: "Daily standup reminder",
    blocks: [
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `📅 Time for your standup. Post your update in <${threadUrl}|today's thread>.\nTap *Draft* and I'll put together a draft from your connected tools.`,
        },
      },
      { type: "actions", elements: buttons },
    ],
  };
}

/** "Researching…" placeholder shown while the draft is generated. */
export function buildLoadingMessage(label = "Researching your activity and drafting your standup…") {
  return {
    text: label,
    blocks: [{ type: "section", text: { type: "mrkdwn", text: `⏳ ${label}` } }],
  };
}

/** The draft DM: the draft text + Confirm/Edit buttons. */
export function buildDraftMessage(draft: string, ctx: StandupContext) {
  const value = JSON.stringify(ctx);
  const body = draft.trim()
    ? draft
    : "_No draft yet. Tap ✏️ Edit to write your update._";
  return {
    text: "Your standup draft is ready for review.",
    blocks: [
      {
        type: "section",
        text: { type: "mrkdwn", text: "*Your standup draft.* Review and post 👇" },
      },
      { type: "section", block_id: DRAFT_BODY_BLOCK, text: { type: "mrkdwn", text: body } },
      { type: "divider" },
      {
        type: "actions",
        elements: [
          {
            type: "button",
            style: "primary",
            text: { type: "plain_text", text: "✅ Confirm & Post", emoji: true },
            action_id: ACTION_CONFIRM,
            value,
          },
          {
            type: "button",
            text: { type: "plain_text", text: "✏️ Edit", emoji: true },
            action_id: ACTION_EDIT,
            value,
          },
        ],
      },
    ],
  };
}

type DraftMessage = {
  blocks?: Array<{ block_id?: string; text?: { text?: string } }>;
};

/** Recover the draft text from a posted draft message, by stable block_id. */
export function extractDraft(message: DraftMessage): string {
  const block = (message.blocks ?? []).find(
    (b) => b.block_id === DRAFT_BODY_BLOCK
  );
  return block?.text?.text ?? "";
}

/** Shown after posting from the user's own Slack account. */
export function buildPostedMessage(draft: string) {
  return {
    text: "Standup posted.",
    blocks: [
      { type: "section", text: { type: "mrkdwn", text: "✅ *Posted to the standup thread.*" } },
      { type: "section", text: { type: "mrkdwn", text: draft } },
    ],
  };
}

/** Fallback when the member has no personal Slack: copyable text + thread link. */
export function buildCopyMessage(draft: string, threadUrl: string) {
  return {
    text: "Copy your standup into the thread.",
    blocks: [
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `Here's your standup. Copy it and paste it into <${threadUrl}|today's thread>:`,
        },
      },
      { type: "section", text: { type: "mrkdwn", text: "```" + draft + "```" } },
      {
        type: "context",
        elements: [
          {
            type: "mrkdwn",
            text: "_Connect your Slack (tap Connect on the reminder) to have me post it for you next time._",
          },
        ],
      },
    ],
  };
}

/** Connect menu: one URL button per unconnected tool (opens its OAuth link). */
export function buildConnectMenu(links: { label: string; url: string }[]) {
  // Slack actions blocks allow max 5 elements; chunk into rows of 5.
  const rows: Record<string, unknown>[] = [];
  for (let i = 0; i < links.length; i += 5) {
    rows.push({
      type: "actions",
      elements: links.slice(i, i + 5).map((l) => ({
        type: "button",
        text: { type: "plain_text", text: `Connect ${l.label}`, emoji: true },
        url: l.url,
      })),
    });
  }
  return {
    text: "Connect tools to enrich your standup drafts.",
    blocks: [
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: "*Connect your tools* so I can draft from your real activity. All optional:",
        },
      },
      ...rows,
    ],
  };
}

/** Edit modal: multiline input prefilled with the current draft. */
export function buildEditModal(
  draft: string,
  ctx: StandupContext,
  dm: { channel: string; ts: string }
) {
  return {
    type: "modal",
    callback_id: MODAL_EDIT_SUBMIT,
    private_metadata: JSON.stringify({ ...ctx, dmChannel: dm.channel, dmTs: dm.ts }),
    title: { type: "plain_text", text: "Edit standup" },
    submit: { type: "plain_text", text: "Save" },
    close: { type: "plain_text", text: "Cancel" },
    blocks: [
      {
        type: "input",
        block_id: EDIT_INPUT_BLOCK,
        label: { type: "plain_text", text: "Your standup update" },
        element: {
          type: "plain_text_input",
          action_id: EDIT_INPUT_ACTION,
          multiline: true,
          initial_value: draft,
        },
      },
    ],
  };
}

import { Composio } from "@composio/core";
import { env } from "../api/_utils/env";

// One-time setup: connect the bot's Slack ("slackbot") account so it can post to
// the channel and DM members. Run with `npx tsx scripts/setup.ts`, or
// `--reconnect` to clear and re-do the OAuth (needed after changing Slack scopes).
const COMPOSIO_BASE_URL = "https://backend.composio.dev";
const TOOLKIT_SLUG = "slackbot";

// Scopes the bot's OAuth *user* token must carry. Composio freezes the scopes at
// connect time, so we check them before connecting and tell the user what to add.
const REQUIRED_USER_SCOPES = ["team:read"];

const log = {
  ok: (msg: string) => console.log(`  ✅ ${msg}`),
  info: (msg: string) => console.log(`  ·  ${msg}`),
  warn: (msg: string) => console.log(`  ⚠️  ${msg}`),
};

function errMessage(err: unknown): string {
  if (err && typeof err === "object") {
    const e = err as {
      error?: { error?: { message?: string }; message?: string };
      message?: string;
    };
    return e.error?.error?.message ?? e.error?.message ?? e.message ?? String(err);
  }
  return String(err);
}

async function main() {
  const RECONNECT = process.argv.includes("--reconnect");

  console.log("\n╭─────────────────────────────────────────────────────────╮");
  console.log("│  Daily Standup Bot: One-Time Setup                       │");
  console.log("╰─────────────────────────────────────────────────────────╯");
  if (RECONNECT) {
    console.log("  (--reconnect: will clear and re-do the bot's Slack auth)");
  }

  const composio = new Composio({ apiKey: env.COMPOSIO_API_KEY });
  const authConfigId = env.COMPOSIO_SLACKBOT_AUTH_CONFIG_ID;

  // Check the auth config requests the scopes the bot needs.
  // READ-ONLY on purpose. GET returns secrets MASKED, and a PATCH that echoes
  // those masked values back overwrites the real client_secret with the mask.
  // So we never write credentials here; we only check and warn.
  const cfgRes = await fetch(`${COMPOSIO_BASE_URL}/api/v3/auth_configs/${authConfigId}`, {
    headers: { "x-api-key": env.COMPOSIO_API_KEY },
  });
  if (cfgRes.ok) {
    const cfg = (await cfgRes.json().catch(() => ({}))) as {
      credentials?: { user_scopes?: string[] };
    };
    const userScopes = cfg.credentials?.user_scopes ?? [];
    const missing = REQUIRED_USER_SCOPES.filter((s) => !userScopes.includes(s));
    if (missing.length > 0) {
      log.warn(`Auth config is missing required user scope(s): ${missing.join(", ")}`);
      console.log(
        "     Add them under the auth config's User Token Scopes in the Composio\n" +
          "     dashboard (Auth Configs → slackbot), then re-run with --reconnect."
      );
    } else {
      log.ok("Auth config has the required user scopes.");
    }
  }

  // Ensure the bot's Slack connection is active.
  const session = await composio.sessions.create("default", {
    authConfigs: { slackbot: authConfigId },
  });

  async function listSlackbotAccounts() {
    try {
      const res = await composio.connectedAccounts.list({
        userIds: ["default"],
        toolkitSlugs: [TOOLKIT_SLUG],
      });
      return res.items;
    } catch {
      return [];
    }
  }

  if (RECONNECT) {
    const accounts = await listSlackbotAccounts();
    if (accounts.length === 0) {
      log.info("No existing connections to clear.");
    } else {
      for (const acc of accounts) {
        try {
          await composio.connectedAccounts.delete(acc.id);
          log.ok(`Removed old connection ${acc.id}.`);
        } catch (err) {
          log.warn(`Could not remove ${acc.id}: ${errMessage(err)}`);
        }
      }
    }
  }

  let connected = false;
  if (!RECONNECT) {
    const toolkits = await session.toolkits({ toolkits: [TOOLKIT_SLUG] });
    connected = !!toolkits.items.find((t) => t.slug === TOOLKIT_SLUG)?.connection
      ?.isActive;
  }

  if (connected) {
    log.ok("Bot is already connected to Slack.");
  } else {
    log.info("Bot is not connected yet. Generating an authorization link…");
    // Manual authentication: authorize() returns a Connect Link, then
    // waitForConnection() resolves once the bot finishes OAuth in the browser.
    // https://docs.composio.dev/docs/manually-authenticating
    const connectionRequest = await session.authorize(TOOLKIT_SLUG);
    if (!connectionRequest.redirectUrl) {
      throw new Error("Composio did not return an authorization link.");
    }

    console.log("\n  Open this URL in your browser to authorize the bot:\n");
    console.log(`    ${connectionRequest.redirectUrl}\n`);
    console.log("  Waiting for you to complete the OAuth flow (Ctrl+C to abort)…");

    const TIMEOUT_MS = 5 * 60 * 1000;
    const account = await connectionRequest.waitForConnection(TIMEOUT_MS);
    log.ok(`Bot connected to Slack (${account.id}).`);
  }

  console.log(`\n${"─".repeat(70)}`);
  console.log("  🎉 Setup complete. Invite the bot to your standup channel and");
  console.log("     point your Slack app's Interactivity Request URL at");
  console.log("     https://<your-deployment>/api/interactivity");
  console.log(`${"─".repeat(70)}\n`);
}

main().catch((err) => {
  console.error(`\n  ❌ ${errMessage(err)}\n`);
  process.exit(1);
});
